class Solution:
    def missingInteger(self, nums: List[int]) -> int:
        i = 1
        while i < len(nums):
            if nums[i] != nums[i - 1] + 1:
                break
            i += 1
        target_sum = sum(nums[:i])
        seen = set(nums)
        x = target_sum
        while x in seen:
            x += 1
        return x
